public boolean endOther(String a, String b) {
    a = a.toLowerCase();
    b = b.toLowerCase();

    int aLen = a.length();
    int bLen = b.length();

    if (aLen == 0 || bLen == 0) {
        return false;
    }

    if (aLen >= bLen) {
        return a.endsWith(b);
    } else {
        return b.endsWith(a);
    }
}

public boolean sameEnds(int[] nums, int n) {
    if (nums.length < n) {
        return false;
    }

    for (int i = 0; i < n; i++) {
        if (nums[i] != nums[nums.length - n + i]) {
            return false;
        }
    }

    return true;
}

